import Dexie, { Table } from 'dexie';

export interface Habit { id: string; name: string; createdAt: number }
export interface CheckIn { id: string; habitId: string; date: string }

export class HabitsDB extends Dexie {
  habits!: Table<Habit, string>;
  checkIns!: Table<CheckIn, string>;

  constructor() {
    super('habits');
    this.version(1).stores({
      habits: 'id, name, createdAt',
      checkIns: 'id, habitId, date',
    });
  }
}

export const db = new HabitsDB();

import { useState } from 'react';
import { useHabit } from '../hooks/useHabit';

export function HabitCard({ habitId }: { habitId: string }) {
  const { habit, streak, checkIn } = useHabit(habitId);
  const [bumped, setBumped] = useState(false);

  return (
    <div className="habit-card">
      <div className="name">{habit.name}</div>
      <div className={`streak ${bumped ? 'bumped' : ''}`}>
        {streak.current} day streak
      </div>
      <button onClick={async () => { await checkIn(); setBumped(true); }}>
        I did it today
      </button>
    </div>
  );
}
